#include <iostream>
#include <string>

class TrafficLight {
public:
    enum class State { Red, Green, Yellow };

    void next() {
        if (m_state == State::Red)    m_state = State::Green;
        else if (m_state == State::Green)  m_state = State::Yellow;
        else                          m_state = State::Red;
    }

    std::string stateName() const {
        if (m_state == State::Red)    return "Red";
        if (m_state == State::Green)  return "Green";
        return "Yellow";
    }

private:
    State m_state{State::Red};
};

int main() {
    int n;
    std::cin >> n;

    TrafficLight light;
    std::cout << light.stateName() << '\n';
    for (int i = 0; i < n; ++i) {
        light.next();
        std::cout << light.stateName() << '\n';
    }
    return 0;
}

